const row = $input.first().json;

const parsedSpecs = JSON.parse(row.specs);

return [{
  json: {
    mcat_id: row.mcat_id,
    mcat_name: row.mcat_name,
    finalized_specs: parsedSpecs.finalized_specs
  }
}];

const data = $input.first().json;
const stepFiles = data?.steps?.step_11_normalizer_output?.root_files ?? [];
const normFiles = data?.normalization?.final_stats ?? [];
const updated = Array.isArray(stepFiles) ? stepFiles.find(f => f?.filename === 'updated_spec_value_counts_cumulative.csv') : null;
const final_ = Array.isArray(normFiles) ? normFiles.find(f => f?.filename === 'final_spec_value_counts_cumulative.csv') : null;
const picked = updated || final_;
if (picked?.url) return [{ json: { target_url: picked.url } }];
return [{ json: { target_url: null } }];

// Process buyer CSV — keep OPTION-LEVEL data (don't aggregate to spec level)
// Each row: spec_name + option_value + prod_count
const allItems = $input.all();
if (!allItems || allItems.length === 0) return [{ json: { buyer_call_options: [] } }];

const options = [];
for (const item of allItems) {
  const row = item.json;
  const spec = row.normalised_spec_name;
  let value = row.normalised_spec_value || '';
  if (row.normalised_spec_value_unit) value = `${value} ${row.normalised_spec_value_unit}`;
  value = value.trim();
  if (!spec || !value) continue;
  const count = Number(row.prod_count || 0);
  options.push({ spec_name: spec, option_value: value, prod_count: count });
}

return [{ json: { buyer_call_options: options } }];

// ============================================================
// BUILD MAPPER INPUT — Collect all option name lists per spec
// Pass raw data through for Join Numbers
// ============================================================

const allItems = $input.all().map(i => i.json);

// ============================================================
// Separate sources
// ============================================================

let buyerCallOptions = [];
let fillRateRows = [];
let searchRows = [];
let specData = null;

for (const item of allItems) {

  // Buyer call dataset
  if (Array.isArray(item.buyer_call_options)) {
    buyerCallOptions = item.buyer_call_options;
    continue;
  }

  // Finalized specs dataset
  if (item.finalized_specs && typeof item.finalized_specs === 'object' && !Array.isArray(item.finalized_specs)) {
    specData = item;
    continue;
  }

  // Fill rate dataset
  if (
    item.option_fill_rate !== undefined ||
    item.product_count !== undefined ||
    item.spec_option_name !== undefined
  ) {
    fillRateRows.push(item);
    continue;
  }

  // Search dataset
  if (
    item.Impression !== undefined ||
    item.impression !== undefined ||
    item.spec_option !== undefined
  ) {
    searchRows.push(item);
    continue;
  }
}

// ============================================================
// Category Info
// ============================================================

const mcatId = specData?.mcat_id || null;
const categoryName = specData?.mcat_name || 'Unknown';
const finSpecs = specData?.finalized_specs || {};

// ============================================================
// Build current options per spec
// ============================================================

const currentSpecOptions = {};

for (const tk of [
  'finalized_primary_specs',
  'finalized_secondary_specs',
  'finalized_tertiary_specs'
]) {

  if (!finSpecs[tk] || !finSpecs[tk].specs) continue;

  for (const spec of finSpecs[tk].specs) {

    const specName = (spec.spec_name || '').toString().trim();

    currentSpecOptions[specName] = {
      options: spec.options || [],
      input_type: spec.input_type || 'radio_button'
    };
  }
}

// ============================================================
// Buyer Call Options
// ============================================================

const callOptionNames = {};

for (const o of buyerCallOptions) {

  const spec = (o.spec_name ?? '').toString().trim();
  const opt = (o.option_value ?? '').toString().trim();

  if (!spec || !opt) continue;

  if (!callOptionNames[spec]) callOptionNames[spec] = [];

  if (!callOptionNames[spec].includes(opt)) {
    callOptionNames[spec].push(opt);
  }
}

// ============================================================
// Fill Rate Options
// ============================================================

const fillOptionNames = {};

for (const r of fillRateRows) {

  const spec = (r.spec_name ?? r['Spec Name'] ?? '').toString().trim();

  const opt = (
    r.spec_option_name ??
    r.normalised_spec_value ??
    r['Spec Value'] ??
    r.option_value ??
    ''
  ).toString().trim();

  if (!spec || !opt) continue;

  if (!fillOptionNames[spec]) fillOptionNames[spec] = [];

  if (!fillOptionNames[spec].includes(opt)) {
    fillOptionNames[spec].push(opt);
  }
}

// ============================================================
// Search Options
// ============================================================

const searchOptionNames = {};

for (const r of searchRows) {

  const spec = (r.spec_name ?? r['Spec Name'] ?? '').toString().trim();

  const opt = (
    r.spec_option ??
    r['Spec Option'] ??
    r.option_value ??
    ''
  ).toString().trim();

  if (!spec || !opt) continue;

  if (!searchOptionNames[spec]) searchOptionNames[spec] = [];

  if (!searchOptionNames[spec].includes(opt)) {
    searchOptionNames[spec].push(opt);
  }
}

// ============================================================
// Output
// ============================================================

return [{
  json: {
    mcat_id: mcatId,
    category_name: categoryName,

    current_spec_options: currentSpecOptions,

    call_option_names: callOptionNames,
    fill_option_names: fillOptionNames,
    search_option_names: searchOptionNames,

    // Raw passthrough for downstream processing
    _raw_call_options: buyerCallOptions,
    _raw_fill_rows: fillRateRows,
    _raw_search_rows: searchRows,
    _raw_finalized_specs: finSpecs
  }
}];

// Parse mapper output — option name mappings
const first = $input.first().json;
const llmOutput = first.output ?? first.text;
if (!llmOutput || typeof llmOutput !== 'string') throw new Error('No output from Option Mapper.');
let clean = llmOutput.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let parsed;
try { parsed = JSON.parse(clean); } catch (e) {
  let repaired = clean.replace(/,\s*([}\]])/g, '$1').replace(/}\s*{/g, '},{').replace(/,\s*,/g, ',').replace(/[\u0000-\u001F]+/g, '');
  try { parsed = JSON.parse(repaired); } catch (err) { throw new Error('Invalid JSON from Mapper.\n' + clean.slice(0, 500)); }
}
return [{ json: { mappings: parsed.spec_option_mappings || [], category_name: parsed.category_name } }];

// ============================================================
// PARSE AUDIT OUTPUT + BUILD FINAL SPECS
// Extract LLM decisions, rebuild spec JSON with cleaned options
// ============================================================

const first = $input.first().json;
const llmOutput = first.output ?? first.text;
if (!llmOutput || typeof llmOutput !== 'string') throw new Error('No output from Audit Agent.');
let clean = llmOutput.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let parsed;
try { parsed = JSON.parse(clean); } catch (e) {
  let repaired = clean.replace(/,\s*([}\]])/g, '$1').replace(/}\s*{/g, '},{').replace(/,\s*,/g, ',').replace(/[\u0000-\u001F]+/g, '');
  try { parsed = JSON.parse(repaired); } catch (err) { throw new Error('Invalid JSON from Audit.\n' + clean.slice(0, 500)); }
}

const mcatId = parsed.mcat_id || $('Build Mapper Input').first().json.mcat_id;
const categoryName = parsed.category_name || $('Build Mapper Input').first().json.category_name;
const rawSpecs = $('Build Mapper Input').first().json._raw_finalized_specs || {};

// Build final option list per spec from LLM decisions
const finalOptionMap = {};
const auditRows = [];

for (const specDec of (parsed.spec_decisions || [])) {
  const specName = specDec.spec_name;
  finalOptionMap[specName] = specDec.final_option_list || [];

  // Flatten for sheet output
  for (const opt of (specDec.options || [])) {
    auditRows.push({
      mcat_id: mcatId,
      category_name: categoryName,
      spec_name: specName,
      option_value: opt.option_value,
      is_current: opt.is_current,
      is_new: false,
      decision: opt.decision,
      merge_into: opt.merge_into || '',
      reason: opt.reason || ''
    });
  }
  for (const newOpt of (specDec.new_options_to_add || [])) {
    auditRows.push({
      mcat_id: mcatId,
      category_name: categoryName,
      spec_name: specName,
      option_value: newOpt.option_value,
      is_current: false,
      is_new: true,
      decision: newOpt.decision,
      merge_into: '',
      reason: newOpt.reason || ''
    });
  }
}

// Rebuild finalized_specs with cleaned options
const updatedSpecs = JSON.parse(JSON.stringify(rawSpecs));
for (const tk of ['finalized_primary_specs','finalized_secondary_specs','finalized_tertiary_specs']) {
  if (!updatedSpecs[tk] || !updatedSpecs[tk].specs) continue;
  for (const spec of updatedSpecs[tk].specs) {
    if (finalOptionMap[spec.spec_name]) {
      spec.options = finalOptionMap[spec.spec_name];
    }
  }
}

return [{
  json: {
    mcat_id: mcatId,
    category_name: categoryName,
    audit_rows: auditRows,
    final_specs: updatedSpecs
  }
}];

const data = $input.first().json;

const { mcat_id, category_name, spec_option_importance } = data;

const rows = [];

for (const spec of spec_option_importance || []) {

  const specName = spec.spec_name;

  for (const opt of spec.options || []) {

    rows.push({
      mcat_id,
      category_name,
      spec_name: specName,
      option_value: opt.option_value,
      importance: opt.importance,
      reason: opt.reason
    });

  }

}

return rows.map(r => ({ json: r }));

// ============================================================
// JOIN OPTION NUMBERS — Use mapper name mapping to pull actual
// numbers from raw source data per option. LLM never touches numbers.
// ============================================================

function norm(v) {
  return (v ?? '')
    .toString()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

const mapperOutput = $('Parse Mapper Output').first().json;
const inputData = $('Build Mapper Input').first().json;

const {
  _raw_call_options,
  _raw_fill_rows,
  _raw_search_rows,
  _raw_finalized_specs
} = inputData;

const mcatId = inputData.mcat_id;
const categoryName = inputData.category_name;

const mappings =
  mapperOutput.mappings ||
  mapperOutput.spec_option_mappings ||
  [];

// ============================================================
// BUILD LOOKUPS
// ============================================================

// CALL DATA
const callLookup = {};

for (const o of _raw_call_options || []) {

  const spec = norm(o.spec_name);
  const opt = norm(o.option_value);

  if (!spec || !opt) continue;

  const key = spec + '|||' + opt;

  callLookup[key] =
    (callLookup[key] || 0) +
    Number(o.prod_count || 0);
}

// ============================================================
// FILL RATE DATA
// ============================================================

const fillLookup = {};

for (const r of _raw_fill_rows || []) {

  const spec = norm(
    r['Spec Name'] ||
    r['spec_name']
  );

  const opt = norm(
    r['spec_option_name'] ||
    r['normalised_spec_value'] ||
    r['Spec Value'] ||
    r['option_value']
  );

  if (!spec || !opt) continue;

  const key = spec + '|||' + opt;

  fillLookup[key] = Math.max(
    fillLookup[key] || 0,
    Number(
      r['option_fill_rate'] ||
      r['spec_fill_rate'] ||
      r['Spec Fill Rate'] ||
      r['fill_rate'] ||
      0
    )
  );
}

// ============================================================
// SEARCH DATA
// ============================================================

const searchLookup = {};

for (const r of _raw_search_rows || []) {

  const spec = norm(
    r['Spec Name'] ||
    r['spec_name']
  );

  const opt = norm(
    r['spec_option'] ||
    r['Spec Option'] ||
    r['option_value']
  );

  if (!spec || !opt) continue;

  const key = spec + '|||' + opt;

  searchLookup[key] =
    (searchLookup[key] || 0) +
    Number(
      r['Impression'] ||
      r['impression'] ||
      r['Total Impressions'] ||
      0
    );
}

// ============================================================
// JOIN NUMBERS USING LLM MAPPING
// ============================================================

const auditTable = [];

for (const specMapping of mappings) {

  const specName = specMapping.spec_name;

  // ------------------------------------------------------------
  // CURRENT OPTIONS
  // ------------------------------------------------------------

  for (const om of (specMapping.option_mappings || [])) {

    let prodCount = 0;
    let fillRate = 0;
    let impressions = 0;

    for (const cn of (om.matched_call_options || [])) {

      const key = norm(specName) + '|||' + norm(cn);

      prodCount += callLookup[key] || 0;
    }

    for (const fn of (om.matched_fill_options || [])) {

      const key = norm(specName) + '|||' + norm(fn);

      fillRate = Math.max(fillRate, fillLookup[key] || 0);
    }

    for (const sn of (om.matched_search_options || [])) {

      const key = norm(specName) + '|||' + norm(sn);

      impressions += searchLookup[key] || 0;
    }

    auditTable.push({
      spec_name: specName,
      option_value: om.current_option,
      is_current: true,
      is_new: false,
      prod_count: prodCount,
      fill_rate: fillRate,
      impression: impressions
    });
  }

  // ------------------------------------------------------------
  // NEW OPTIONS
  // ------------------------------------------------------------

  for (const newOpt of (specMapping.new_options || [])) {

    let prodCount = 0;
    let fillRate = 0;
    let impressions = 0;

    const seenIn = newOpt.seen_in || [];
    const rawValues = newOpt.raw_source_values || [];

    for (const raw of rawValues) {

      const key = norm(specName) + '|||' + norm(raw);

      if (seenIn.includes('call')) {
        prodCount += callLookup[key] || 0;
      }

      if (seenIn.includes('fill')) {
        fillRate = Math.max(fillRate, fillLookup[key] || 0);
      }

      if (seenIn.includes('search')) {
        impressions += searchLookup[key] || 0;
      }
    }

    auditTable.push({
      spec_name: specName,
      option_value: newOpt.option_value,
      is_current: false,
      is_new: true,
      prod_count: prodCount,
      fill_rate: fillRate,
      impression: impressions
    });
  }
}

// ============================================================
// OUTPUT
// ============================================================

return [{
  json: {
    mcat_id: mcatId,
    category_name: categoryName,
    audit_table: auditTable,
    _raw_finalized_specs: _raw_finalized_specs
  }
}];

// -----------------------------------------------------
// SPLIT CURRENT OPTIONS AND NEW OPTIONS BY SPEC
// -----------------------------------------------------

const data = $input.first().json;

const audit = data.audit_table || [];

const currentSpecs = {};
const newSpecs = {};

// group rows by spec
for (const row of audit) {

  const spec = row.spec_name;

  if (row.is_current) {

    if (!currentSpecs[spec]) currentSpecs[spec] = [];

    currentSpecs[spec].push({
      option_value: row.option_value,
      prod_count: row.prod_count,
      fill_rate: row.fill_rate,
      impression: row.impression
    });

  }

  if (row.is_new) {

    if (!newSpecs[spec]) newSpecs[spec] = [];

    newSpecs[spec].push({
      option_value: row.option_value,
      prod_count: row.prod_count,
      fill_rate: row.fill_rate,
      impression: row.impression
    });

  }

}

// convert to arrays
const current_specs = Object.keys(currentSpecs).map(spec => ({
  spec_name: spec,
  options: currentSpecs[spec]
}));

const new_specs = Object.keys(newSpecs).map(spec => ({
  spec_name: spec,
  options: newSpecs[spec]
}));


return [
  {
    json: {
      mcat_id: data.mcat_id,
      category_name: data.category_name,
      current_specs,
      new_specs,
      _raw_finalized_specs: data._raw_finalized_specs
    }
  }
];

const data = $input.first().json;

const rows = [];

function processSpecs(specs, type) {
  for (const spec of specs) {
    for (const opt of spec.options) {
      rows.push({
        mcat_id: data.mcat_id,
        category_name: data.category_name,
        spec_type: type,
        spec_name: spec.spec_name,
        option_value: opt.option_value,
        prod_count: opt.prod_count ?? 0,
        fill_rate: opt.fill_rate ?? 0,
        impression: opt.impression ?? 0
      });
    }
  }
}

// process current specs
processSpecs(data.current_specs, "current");

// process new specs
processSpecs(data.new_specs, "new");

return rows.map(r => ({ json: r }));

const input = $input.first().json;

const { mcat_id, category_name, current_specs } = input;

const specMap = {};

for (const spec of current_specs || []) {

  const specName = spec.spec_name;

  if (!specMap[specName]) {
    specMap[specName] = {
      spec_name: specName,
      options: []
    };
  }

  for (const opt of spec.options || []) {

    const option = opt.option_value;

    const prod = Number(opt.prod_count || 0);
    const fill = Number(opt.fill_rate || 0);
    const imp  = Number(opt.impression || 0);

    const callSignal   = prod > 0;
    const sellerSignal = fill > 0;
    const searchSignal = imp > 0;

    const signalSources =
      (callSignal ? 1 : 0) +
      (sellerSignal ? 1 : 0) +
      (searchSignal ? 1 : 0);

    let importance;

    if (
      signalSources >= 2 ||
      fill >= 3 ||
      prod >= 2
    ) {
      importance = "HIGH_IMPORTANCE";
    } else {
      importance = "LOW_IMPORTANCE";
    }

    specMap[specName].options.push({
      option_value: option,
      prod_count: prod,
      fill_rate: fill,
      impression: imp,
      importance,
      reason: `ProdCount:${prod} FillRate:${fill} Imp:${imp} SignalSources:${signalSources}`
    });
  }
}

return [{
  json: {
    mcat_id,
    category_name,
    spec_option_importance: Object.values(specMap)
  }
}];

const input = $input.first().json;

const category = input.category_name;
const mappings = input.mappings;

const rows = [];

for (const spec of mappings) {

  const specName = spec.spec_name;

  // CURRENT OPTION MAPPINGS
  for (const map of spec.option_mappings || []) {

    const canonical = map.current_option;

    for (const v of map.matched_call_options || []) {
      rows.push({
        category_name: category,
        spec_name: specName,
        option_type: "current_option",
        option_value: v,
        source: "call",
        mapped_to: canonical,
        reason: "",
        raw_source_values: ""
      });
    }

    for (const v of map.matched_fill_options || []) {
      rows.push({
        category_name: category,
        spec_name: specName,
        option_type: "current_option",
        option_value: v,
        source: "fill",
        mapped_to: canonical,
        reason: "",
        raw_source_values: ""
      });
    }

    for (const v of map.matched_search_options || []) {
      rows.push({
        category_name: category,
        spec_name: specName,
        option_type: "current_option",
        option_value: v,
        source: "search",
        mapped_to: canonical,
        reason: "",
        raw_source_values: ""
      });
    }

  }

  // NEW OPTIONS
  for (const opt of spec.new_options || []) {

    rows.push({
      category_name: category,
      spec_name: specName,
      option_type: "new_option",
      option_value: opt.option_value,
      source: (opt.seen_in || []).join(","),
      mapped_to: "",
      reason: "",
      raw_source_values: (opt.raw_source_values || []).join(", ")
    });

  }

  // JUNK OPTIONS
  for (const j of spec.junk_options || []) {

    rows.push({
      category_name: category,
      spec_name: specName,
      option_type: "junk_option",
      option_value: j.value,
      source: j.source,
      mapped_to: "",
      reason: j.reason,
      raw_source_values: ""
    });

  }

}

return rows.map(r => ({ json: r }));
